Active Directory est la cible principale des attaquants dans les environnements Windows. Les techniques courantes :

- **Pass-the-Hash / Pass-the-Ticket** : réutilisation de hashes NTLM ou tickets Kerberos
- **Kerberoasting** : demander des tickets de service et cracker offline
- **DCSync** : récupérer les hashes de tous les comptes AD
- **BloodHound paths** : chemins d'escalade de privilèges
- **Golden/Silver Tickets** : forger des tickets Kerberos

```powershell
# Vérifier si le module AD est disponible
if (Get-Module -ListAvailable -Name ActiveDirectory) {
    Import-Module ActiveDirectory
    Write-Host "Module AD chargé"
} else {
    Write-Host "Module AD non disponible (RSAT requis)"
    Write-Host "Install-WindowsFeature RSAT-AD-PowerShell"
}

# Informations de base sur le domaine
try {
    $domain = Get-ADDomain
    Write-Host "Domaine : $($domain.DNSRoot)"
    Write-Host "DC(s) : $($domain.PDCEmulator)"
} catch {
    Write-Host "Non joint à un domaine AD"
}
```

```powershell
# Analyser les comptes Domain Admin et Enterprise Admin

function Get-ComptesSuspects {
    try {
        # Membres des groupes sensibles
        $groupesSensibles = @(
            'Domain Admins', 'Enterprise Admins', 
            'Schema Admins', 'Administrators'
        )

        foreach ($groupe in $groupesSensibles) {
            try {
                $membres = Get-ADGroupMember -Identity $groupe -Recursive -ErrorAction Stop
                Write-Host "[$groupe] : $($membres.Count) membre(s)"
                $membres | ForEach-Object {
                    $user = Get-ADUser $_.SamAccountName -Properties LastLogonDate, PasswordLastSet, Enabled -ErrorAction SilentlyContinue
                    if ($user) {
                        $flag = if (-not $user.Enabled) { ' [DÉSACTIVÉ]' }
                                elseif ($user.PasswordLastSet -lt (Get-Date).AddDays(-90)) { ' [MOT DE PASSE ANCIEN]' }
                                else { '' }
                        Write-Host "  - $($user.SamAccountName) | LastLogon: $($user.LastLogonDate)$flag"
                    }
                }
            } catch {
                Write-Host "[$groupe] : Non accessible"
            }
        }
    } catch {
        Write-Host "Erreur : $_"
    }
}

Get-ComptesSuspects

# Comptes avec LastLogon > 90 jours mais encore actifs (potentiels comptes fantômes)
try {
    $inactifs = Get-ADUser -Filter {Enabled -eq $true -and LastLogonDate -lt ((Get-Date).AddDays(-90))} `
        -Properties LastLogonDate | Select-Object SamAccountName, LastLogonDate
    Write-Host "`nComptes inactifs (>90j) mais actifs : $($inactifs.Count)"
} catch {
    Write-Host "(Module AD requis pour cette analyse)"
}
```

```powershell
# Détecter les comptes vulnérables au Kerberoasting
# (ServicePrincipalName défini + compte utilisateur)

function Find-KerberoastableAccounts {
    try {
        $comptes = Get-ADUser -Filter {ServicePrincipalName -ne "$null" -and Enabled -eq $true} `
            -Properties ServicePrincipalName, PasswordLastSet, Description

        Write-Host "Comptes Kerberoastable : $($comptes.Count)"
        $comptes | ForEach-Object {
            $ancienMDP = ($_.PasswordLastSet -lt (Get-Date).AddDays(-180))
            $flag = if ($ancienMDP) { ' [MDP ANCIEN - PRIORITAIRE]' } else { '' }
            Write-Host "  $($_.SamAccountName) | SPN: $($_.ServicePrincipalName -join ',')$flag"
        }
    } catch {
        Write-Host "(Module AD requis)"
    }
}

# Détecter les comptes AS-REP Roastable
# (DoesNotRequirePreAuth = True → hash récupérable sans authentification)
function Find-ASREPRoastableAccounts {
    try {
        $comptes = Get-ADUser -Filter {DoesNotRequirePreAuth -eq $true -and Enabled -eq $true}
        Write-Host "`nComptes AS-REP Roastable : $($comptes.Count)"
        if ($comptes.Count -gt 0) {
            Write-Host "[CRITIQUE] Ces comptes peuvent être attaqués sans credentials !"
            $comptes | ForEach-Object { Write-Host "  $($_.SamAccountName)" }
        }
    } catch {
        Write-Host "(Module AD requis)"
    }
}

Find-KerberoastableAccounts
Find-ASREPRoastableAccounts
