```powershell
# Détecter les patterns de mouvement latéral via les logs

$debut = (Get-Date).AddHours(-4)

# EventID 4769 : Ticket de service Kerberos demandé (Kerberoasting)
$tickets = Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 4769
    StartTime = $debut
} -ErrorAction SilentlyContinue

if ($tickets) {
    Write-Host "Tickets Kerberos service demandés (4h) : $($tickets.Count)"

    # Comptes demandant beaucoup de tickets (IOC Kerberoasting)
    $parCompte = $tickets | ForEach-Object {
        if ($_.Message -match 'Account Name:\s+(\S+)@') { $Matches[1] }
    } | Group-Object | Sort-Object Count -Descending

    $parCompte | Select-Object -First 5 | ForEach-Object {
        $flag = if ($_.Count -gt 20) { ' [KERBEROASTING PROBABLE]' } else { '' }
        Write-Host "  $($_.Name) : $($_.Count) ticket(s)$flag"
    }
}

# EventID 4648 : Logon with explicit credentials (Pass-the-Hash)
$explicit = Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 4648
    StartTime = $debut
} -ErrorAction SilentlyContinue

Write-Host "`nConnexions credentials explicites (4648) : $(($explicit).Count)"
